public class BadKey {
    @Override public int hashCode() { return 1; } // catastrophic
}

// GOOD: well-distributed
public class GoodKey {
    private String name; private int id;
    @Override public int hashCode() { return Objects.hash(name, id); }
    @Override public boolean equals(Object o) {
        if (!(o instanceof GoodKey)) return false;
        GoodKey k = (GoodKey) o;
        return id == k.id && Objects.equals(name, k.name);
    }
}

