// Cache stampede protection with per-key mutex
public String getCachedValue(String key) {
    String cached = redis.get(key);
    if (cached == null) {
        synchronized (getMutex(key)) { // per-key lock
            cached = redis.get(key);   // double-check
            if (cached == null) {
                cached = expensiveCompute(key);
                redis.setex(key, 300, cached);
            }
        }
    }
    return cached;
}

