@Test void testConcurrent() throws Exception {
    int threads = 100;
    CountDownLatch start = new CountDownLatch(1);
    CountDownLatch done  = new CountDownLatch(threads);
    for (int i = 0; i < threads; i++) {
        new Thread(() -> { try { start.await(); service.increment(); }
            catch (Exception e) {} finally { done.countDown(); } }).start();
    }
    start.countDown();
    done.await();
    assertEquals(threads, service.getCount());
}

